select c.id, c.content_id, c.parent_id, c.comment_text, c.anonymous_id, u.avatar, c.like_count, c.comment_status, c.create_time 
from comment c left join user u on c.anonymous_id = u.anonymous_id
where c.id = #{id}

select c.id, c.content_id, c.parent_id, c.comment_text, c.anonymous_id, u.avatar, c.like_count, c.comment_status, c.create_time 
from comment c left join user u on c.anonymous_id = u.anonymous_id
where c.anonymous_id = #{anonymousId} 
order by c.create_time desc 
limit #{pageSize} offset #{offset}

select c.id, c.content_id, c.parent_id, c.comment_text, c.anonymous_id, u.avatar, c.like_count, c.comment_status, c.create_time 
from comment c left join user u on c.anonymous_id = u.anonymous_id
where 1=1

    and comment_status = #{status}


    and create_time >= #{startTime}


    and create_time <= #{endTime}

order by create_time desc 
limit #{pageSize} offset #{offset}

select count(*) from comment 
where 1=1

    and comment_status = #{status}


    and create_time >= #{startTime}


    and create_time <= #{endTime}

